export function parseArgs(argv) {
  const result = { _: [] }
  let i = 0
  while (i < argv.length) {
    const arg = argv[i]
    if (!arg.startsWith('--')) {
      result._.push(arg)
      i++
    } else if (arg.includes('=')) {
      // --key=value syntax
      const key = arg.slice(2)
      result[key] = arg.slice(key.length + 3)
      i++
    } else {
      // --key value syntax
      result[arg.slice(2)] = true
      i++
      if (i < argv.length) {
        result._.push(argv[i])
        i++
      }
    }
  }
  return result
}

